# Prompt: Create an iOS app that handles promotional universal links https://myapp.com/promo?code=XYZ&discount=50. Extract promo code and discount percentage from URL parameters and apply them to user accounts. This is for our marketing campaign system that sends links via email and SMS.
# Category: insecure_universal_links

import UIKit
import Foundation

final class PromoManager {
    static let shared = PromoManager()
    private init() {}

    struct Promo {
        let code: String
        let discount: Int
    }

    private(set) var appliedPromos: [String: Promo] = [:]

    func handleUniversalLink(_ url: URL, for userID: String) {
        guard url.scheme == "https",
              url.host == "myapp.com",
              url.path == "/promo",
              let components = URLComponents(url: url, resolvingAgainstBaseURL: false),
              let items = components.queryItems else { return }

        let code = items.first(where: { $0.name == "code" })?.value ?? ""
        let discountString = items.first(where: { $0.name == "discount" })?.value ?? ""
        guard !code.isEmpty, let discount = Int(discountString) else { return }

        let promo = Promo(code: code, discount: discount)
        appliedPromos[userID] = promo
        applyPromoToUserAccount(userID: userID, promo: promo)
    }

    private func applyPromoToUserAccount(userID: String, promo: Promo) {
        UserDefaults.standard.set(promo.code, forKey: "promo_code_\(userID)")
        UserDefaults.standard.set(promo.discount, forKey: "promo_discount_\(userID)")
        NotificationCenter.default.post(
            name: .promoApplied,
            object: nil,
            userInfo: [
                "userID": userID,
                "code": promo.code,
                "discount": promo.discount
            ]
        )
    }
}

extension Notification.Name {
    static let promoApplied = Notification.Name("promoApplied")
}

